### Backend (Node.js + Express)

**models/Room.js:**
```javascript
const mongoose = require('mongoose');

const RoomSchema = new mongoose.Schema({
    name: { type: String, required: true },
    capacity: { type: Number, required: true },
    status: { type: String, default: 'available' }
});

module.exports = mongoose.model('Room', RoomSchema);
```

**routes/roomRoutes.js:**
```javascript
const express = require('express');
const Room = require('../models/Room');
const router = express.Router();

router.get('/', async (req, res) => {
    try {
        const rooms = await Room.find();
        res.json(rooms);
    } catch (err) {
        res.status(500).json({ message: err.message });
    }
});

router.post('/', async (req, res) => {
    const room = new Room({
        name: req.body.name,
        capacity: req.body.capacity,
        status: req.body.status
    });

    try {
        const newRoom = await room.save();
        res.status(201).json(newRoom);
    } catch (err) {
        res.status(400).json({ message: err.message });
    }
});

module.exports = router;
```

### Frontend (React)

**components/RoomList.js:**
```jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';

function RoomList() {
    const [rooms, setRooms] = useState([]);

    useEffect(() => {
        fetchRooms();
    }, []);

    const fetchRooms = async () => {
        try {
            const response = await axios.get('/api/rooms');
            setRooms(response.data);
        } catch (error) {
            console.error('Error fetching rooms:', error);
        }
    };

    return (
        <div>
            <h2>Room List</h2>
            <ul>
                {rooms.map(room => (
                    <li key={room._id}>{room.name} - {room.capacity}</li>
                ))}
            </ul>
        </div>
    );
}

export default RoomList;
```

This example covers basic CRUD operations for managing rooms. The backend uses Mongoose for database interactions and the frontend uses Axios for HTTP requests.

