from .managers import MasterKeyManager, EncryptionManager, DecryptionManager

class TOTPDevice(models.Model):
    key = models.BinaryField()
    provider = models.CharField(max_length=50)

    @property
    def master_key(self):
        return MasterKeyManager().derive_key(self.id)

    @property
